function w(t,f,a){const o=f/12/100,e=a*12;let u=0;o===0?u=t*e:u=t*((Math.pow(1+o,e)-1)/o)*(1+o);const r=t*e,d=u-r,s=[];for(let c=1;c<=a;c++){const n=c*12;let l=0;o===0?l=t*n:l=t*((Math.pow(1+o,n)-1)/o)*(1+o),s.push({year:c,invested:t*n,returns:l-t*n,total:l})}return{investedAmount:r,estimatedReturns:d,totalValue:u,yearlyBreakdown:s}}function V(t,f,a,o=12){const e=f/100,u=o,r=t*Math.pow(1+e/u,u*a),d=t,s=r-d,c=[];for(let n=1;n<=a;n++){const l=t*Math.pow(1+e/u,u*n);c.push({year:n,invested:t,returns:l-t,total:l})}return{investedAmount:d,estimatedReturns:s,totalValue:r,yearlyBreakdown:c}}function i(t,f,a){const o=f/100;let e=0;const u=[];for(let s=1;s<=a;s++)e=(e+t)*(1+o),u.push({year:s,invested:t*s,returns:e-t*s,total:e});const r=t*a,d=e-r;return{investedAmount:r,estimatedReturns:d,totalValue:e,yearlyBreakdown:u}}export{V as l,i as p,w as s};
